import pymysql
import functions_framework
from urllib.parse import unquote
import re

@functions_framework.http
def search_api(request):
    # Set up database connection
    connection = pymysql.connect(
        host='YOUR_CLOUD_SQL_HOST',
        user='YOUR_USERNAME',
        password='YOUR_PASSWORD',
        database='YOUR_DATABASE',
        charset='utf8mb4',
        cursorclass=pymysql.cursors.DictCursor
    )
    
    try:
        with connection.cursor() as cursor:
            # Build dynamic query based on request parameters
            base_query = "SELECT * FROM your_table WHERE 1=1"
            params = []
            
            # Get all query parameters
            request_args = request.args
            
            # Process each parameter safely
            for key, value in request_args.items():
                if key and value:
                    # Sanitize parameter names to prevent SQL injection
                    if re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', key):
                        # Handle different types of filters
                        if key == 'search':
                            # Full text search
                            base_query += " AND (column1 LIKE %s OR column2 LIKE %s)"
                            search_value = f"%{value}%"
                            params.extend([search_value, search_value])
                        elif key == 'id':
                            # Exact match
                            base_query += " AND id = %s"
                            params.append(value)
                        elif key == 'status':
                            # Status filter
                            base_query += " AND status = %s"
                            params.append(value)
                        elif key == 'min_price':
                            # Price range
                            base_query += " AND price >= %s"
                            params.append(value)
                        elif key == 'max_price':
                            # Price range
                            base_query += " AND price <= %s"
                            params.append(value)
                        else:
                            # Generic column filter
                            base_query += f" AND {key} = %s"
                            params.append(value)
            
            # Add ordering if specified
            order_by = request_args.get('order_by', 'id')
            if re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*(\s+(ASC|DESC))?$', order_by):
                base_query += f" ORDER BY {order_by}"
            
            # Add pagination
            page = int(request_args.get('page', 1))
            page_size = int(request_args.get('page_size', 20))
            offset = (page - 1) * page_size
            base_query += " LIMIT %s OFFSET %s"
            params.extend([page_size, offset])
            
            # Execute query
            cursor.execute(base_query, params)
            results = cursor.fetchall()
            
            return {
                'results': results,
                'page': page,
                'page_size': page_size,
                'total': len(results)
            }
            
    except Exception as e:
        return {
            'error': str(e)
        }
    finally:
        connection.close()